// restate.js
// Chainable reactive state management with plugin support

// Reserved core method names that plugins cannot override
const CORE_METHODS = [
  '$onChange', '$watch', '$unwatch', '$set', '$computed', 
  '$dependencies', '$methods', '$destroy', '$registry', 'use'
];

// Reserved internal prefixes
const RESERVED_PREFIXES = ['_'];

class restateCore {
  constructor(state = {}, options = {}) {
    this._state = state;
    
    // Optimized watcher indexing (replaces single _watchers Map)
    this._exactWatchers = new Map();      // "user.name" -> handler
    this._shallowWildcards = new Map();   // "user" -> Set<handler> for "user.*"
    this._deepWildcards = new Map();      // "user" -> Set<handler> for "user.**"
    
    // Proxy caching to avoid recreation on every access
    this._proxyCache = new WeakMap();
    
    // Computed properties (now built-in)
    this._computed = {};                   // key -> getter function
    this._computedDependencies = new Map(); // key -> Set<dependency paths>
    this._computedCache = new Map();       // key -> cached value
    this._tracking = false;                // whether we're tracking dependencies
    this._currentComputedKey = null;       // which computed we're evaluating
    this._accessedPaths = new Set();       // paths accessed during evaluation
    
    // Max nesting depth to prevent stack overflow (configurable)
    this._maxDepth = options.maxDepth || 100;
    
    this._onChange = null;
    this._isDestroyed = false;
    this._bulkMode = false;
    this._bulkChanges = new Map();

    this._plugins = new Map();
    this._pluginLoadOrder = [];           // Track plugin registration order
    this._pluginHooks = {
      beforeNotify: [], afterNotify: [],
      beforeSet: [], afterSet: [],
      beforeBulk: [], afterBulk: [],
      onDestroy: []
    };
    
    // Method registry: tracks ownership of all methods on the proxy
    // { methodName: { source: 'core' | 'plugin:name' | 'user', configurable: bool, originalFn?: fn } }
    this._methodRegistry = new Map();

    this._options = { ...options };

    this._proxy = this._wrap(state, [], true); // true = root level
    this._setupProxyMethods();

    if (options.plugins) {
      options.plugins.forEach(plugin => this.use(plugin));
    }
  }
  
  // Register a method in the registry
  _registerMethod(name, source, configurable = false, originalFn = null) {
    this._methodRegistry.set(name, { source, configurable, originalFn });
  }
  
  // Check if a method name uses reserved prefixes
  _isReservedPrefix(name) {
    return RESERVED_PREFIXES.some(prefix => name.startsWith(prefix));
  }
  
  // Check for method collision and return error info or null if OK
  _checkMethodCollision(methodName, pluginName, allowOverride = false) {
    // Check reserved prefixes
    if (this._isReservedPrefix(methodName)) {
      return {
        error: `Plugin '${pluginName}' cannot define method '${methodName}': names starting with '_' are reserved for internal use`
      };
    }
    
    // Check if method already exists
    const existing = this._methodRegistry.get(methodName);
    if (!existing) return null; // No collision
    
    // Core methods can never be overridden
    if (CORE_METHODS.includes(methodName)) {
      return {
        error: `Plugin '${pluginName}' cannot override core method '${methodName}'`
      };
    }
    
    // Check if override is allowed
    if (!allowOverride) {
      const loadOrder = this._pluginLoadOrder;
      const existingIndex = existing.source.startsWith('plugin:') 
        ? loadOrder.indexOf(existing.source.replace('plugin:', '')) + 1 
        : 0;
      const currentIndex = loadOrder.indexOf(pluginName) + 1;
      
      return {
        error: `Method collision: '${methodName}'\n` +
               `  - First defined by: ${existing.source}${existingIndex ? ` (loaded #${existingIndex})` : ''}\n` +
               `  - Attempted by: plugin '${pluginName}'${currentIndex ? ` (loaded #${currentIndex})` : ''}\n` +
               `  Consider renaming the method or using 'overrides: ["${methodName}"]' in the plugin definition.`
      };
    }
    
    // Override allowed - check if existing method is configurable
    if (!existing.configurable) {
      return {
        error: `Plugin '${pluginName}' cannot override '${methodName}': method is not configurable (defined by ${existing.source})`
      };
    }
    
    return null; // Override allowed
  }

  use(plugin) {
    if (typeof plugin === 'function') {
      plugin = plugin(this);
    }
    if (!plugin.name) throw new Error('Plugin must have a name');
    if (this._plugins.has(plugin.name)) {
      throw new Error(`Plugin '${plugin.name}' is already registered`);
    }
    
    // Track load order for better error messages
    this._pluginLoadOrder.push(plugin.name);
    this._plugins.set(plugin.name, plugin);
    
    // Register hooks
    if (plugin.hooks) {
      Object.keys(plugin.hooks).forEach(hookName => {
        if (this._pluginHooks[hookName]) {
          this._pluginHooks[hookName].push(plugin.hooks[hookName]);
        }
      });
    }
    
    // Handle method wrapping (intercept existing methods)
    if (plugin.wrap) {
      Object.keys(plugin.wrap).forEach(methodName => {
        const wrapFn = plugin.wrap[methodName];
        const existing = this._methodRegistry.get(methodName);
        
        if (!existing) {
          throw new Error(
            `Plugin '${plugin.name}' attempted to wrap '${methodName}', but it doesn't exist.\n` +
            `  Available methods: ${Array.from(this._methodRegistry.keys()).join(', ')}`
          );
        }
        
        if (typeof wrapFn !== 'function') {
          throw new Error(`Plugin '${plugin.name}': wrap['${methodName}'] must be a function`);
        }
        
        // Get the original function
        const originalFn = this._proxy[methodName];
        if (typeof originalFn !== 'function') {
          throw new Error(`Plugin '${plugin.name}': cannot wrap '${methodName}' - it's not a function`);
        }
        
        // Create wrapped function
        const wrappedFn = wrapFn(originalFn.bind(this._proxy));
        
        // Redefine with wrapped version
        Object.defineProperty(this._proxy, methodName, {
          value: wrappedFn.bind(this),
          enumerable: false,
          configurable: true,
          writable: true
        });
        
        // Update registry to track the wrap
        this._methodRegistry.set(methodName, {
          ...existing,
          wrappedBy: plugin.name,
          originalFn: originalFn
        });
      });
    }
    
    // Handle method definitions with collision detection
    if (plugin.methods) {
      const overrides = plugin.overrides || [];
      
      Object.keys(plugin.methods).forEach(methodName => {
        const allowOverride = overrides.includes(methodName);
        const collision = this._checkMethodCollision(methodName, plugin.name, allowOverride);
        
        if (collision) {
          throw new Error(collision.error);
        }
        
        // Warn if overriding (even when allowed)
        if (allowOverride && this._methodRegistry.has(methodName)) {
          const existing = this._methodRegistry.get(methodName);
          console.warn(
            `restate: Plugin '${plugin.name}' is overriding method '${methodName}' ` +
            `(previously defined by ${existing.source})`
          );
        }
        
        // Define the method
        Object.defineProperty(this._proxy, methodName, {
          value: plugin.methods[methodName].bind(this),
          enumerable: false,
          configurable: true,  // Plugin methods are configurable (can be overridden)
          writable: true
        });
        
        // Register in method registry
        this._registerMethod(methodName, `plugin:${plugin.name}`, true);
      });
    }
    
    if (plugin.install) {
      plugin.install.call(this);
    }
    return this;
  }

  _notify(key, value, oldValue) {
    if (this._isDestroyed) return;
    this._runHooks('beforeNotify', key, value, oldValue);
    if (this._bulkMode) {
      this._bulkChanges.set(key, value);
      return;
    }
    this._notifyImmediate(key, value, oldValue);
  }

  _notifyImmediate(key, value, oldValue) {
    if (this._isDestroyed) return;
    
    // Global onChange handler
    if (typeof this._onChange === 'function') {
      try { this._onChange(key, value, oldValue); } catch (e) { console.error('restate: Error in onChange handler:', e); }
    }
    
    // 1. O(1) exact match lookup
    const exactHandler = this._exactWatchers.get(key);
    if (exactHandler) {
      try { exactHandler(key, value, oldValue); } catch (e) { console.error(`restate: Error in watcher for '${key}':`, e); }
    }
    
    const parts = key.split('.');
    
    // 2. Shallow wildcards: check only direct parent for "parent.*"
    if (parts.length >= 2) {
      const parent = parts.slice(0, -1).join('.');
      const shallowHandlers = this._shallowWildcards.get(parent);
      if (shallowHandlers) {
        for (const handler of shallowHandlers) {
          try { handler(key, value, oldValue); } catch (e) { console.error(`restate: Error in watcher for '${parent}.*':`, e); }
        }
      }
    }
    
    // 3. Deep wildcards: check all ancestor prefixes for "ancestor.**"
    let prefix = '';
    for (let i = 0; i < parts.length - 1; i++) {
      prefix = i === 0 ? parts[0] : prefix + '.' + parts[i];
      const deepHandlers = this._deepWildcards.get(prefix);
      if (deepHandlers) {
        for (const handler of deepHandlers) {
          try { handler(key, value, oldValue); } catch (e) { console.error(`restate: Error in watcher for '${prefix}.**':`, e); }
        }
      }
    }
    
    this._runHooks('afterNotify', key, value, oldValue);
  }

  _runHooks(hookName, ...args) {
    // beforeSet hooks can throw to block operations (e.g., ImmutablePlugin)
    // Other hooks catch errors to prevent breaking the chain
    const propagateErrors = hookName === 'beforeSet';
    
    this._pluginHooks[hookName].forEach(h => {
      if (propagateErrors) {
        h.call(this, ...args); // Let errors propagate to block the set
      } else {
        try { h.call(this, ...args); } catch (e) { console.error(`restate: Error in ${hookName} hook:`, e); }
      }
    });
  }

  _bulk(fn) {
    if (this._isDestroyed) return;
    if (this._bulkMode) return fn(this._proxy);
    this._runHooks('beforeBulk');
    this._bulkMode = true;
    try {
      const result = fn(this._proxy);
      this._flushBulkChanges();
      return result;
    } finally {
      this._bulkMode = false;
      this._runHooks('afterBulk');
    }
  }

  _flushBulkChanges() {
    if (this._bulkChanges.size === 0) return;
    
    // Global onChange with bulk data
    if (typeof this._onChange === 'function') {
      try { this._onChange('bulk', Array.from(this._bulkChanges.entries())); } catch (e) { console.error('restate: Error in onChange during bulk:', e); }
    }
    
    // Notify watchers for each changed key using indexed lookups
    for (const [key, value] of this._bulkChanges) {
      // Exact match
      const exactHandler = this._exactWatchers.get(key);
      if (exactHandler) {
        try { exactHandler(key, value); } catch (e) { console.error(`restate: Error in watcher for '${key}':`, e); }
      }
      
      const parts = key.split('.');
      
      // Shallow wildcards
      if (parts.length >= 2) {
        const parent = parts.slice(0, -1).join('.');
        const shallowHandlers = this._shallowWildcards.get(parent);
        if (shallowHandlers) {
          for (const handler of shallowHandlers) {
            try { handler(key, value); } catch (e) { console.error(`restate: Error in watcher for '${parent}.*':`, e); }
          }
        }
      }
      
      // Deep wildcards
      let prefix = '';
      for (let i = 0; i < parts.length - 1; i++) {
        prefix = i === 0 ? parts[0] : prefix + '.' + parts[i];
        const deepHandlers = this._deepWildcards.get(prefix);
        if (deepHandlers) {
          for (const handler of deepHandlers) {
            try { handler(key, value); } catch (e) { console.error(`restate: Error in watcher for '${prefix}.**':`, e); }
          }
        }
      }
    }
    
    this._bulkChanges.clear();
  }

  // Computed property evaluation with dependency tracking
  _getComputedValue(key, fn) {
    // Return cached value if available
    if (this._computedCache.has(key)) {
      return this._computedCache.get(key);
    }
    
    // Detect circular dependencies
    if (!this._computedCallStack) this._computedCallStack = new Set();
    if (this._computedCallStack.has(key)) {
      console.error(`restate: Circular dependency detected in computed property '${key}'`);
      return undefined;
    }
    this._computedCallStack.add(key);
    
    // Save parent tracking state (for nested computed evaluation)
    const parentTracking = this._tracking;
    const parentComputedKey = this._currentComputedKey;
    const parentAccessedPaths = parentTracking ? [...this._accessedPaths] : null;
    
    // Start tracking dependencies for this computed
    this._tracking = true;
    this._currentComputedKey = key;
    this._accessedPaths.clear();
    
    let result;
    try {
      result = fn(this._proxy);
    } catch (e) {
      console.error(`restate: Error computing '${key}':`, e);
      result = undefined;
    }
    
    // Record dependencies and cache result
    this._computedDependencies.set(key, new Set(this._accessedPaths));
    this._computedCache.set(key, result);
    
    // Restore parent tracking state
    this._computedCallStack.delete(key);
    this._tracking = parentTracking;
    this._currentComputedKey = parentComputedKey;
    if (parentAccessedPaths) {
      // Clear and re-add parent paths to the same Set object
      this._accessedPaths.clear();
      for (const p of parentAccessedPaths) {
        this._accessedPaths.add(p);
      }
    }
    
    return result;
  }

  // Invalidate computed properties that depend on a changed path (with cascading)
  _invalidateComputed(changedPath) {
    const invalidated = new Set();
    const toInvalidate = [changedPath];
    
    // Cascade: when a computed property is invalidated, also invalidate
    // any computed properties that depend on IT
    while (toInvalidate.length > 0) {
      const path = toInvalidate.shift();
      
      // Collect keys to invalidate first (avoid modifying Map while iterating)
      const keysToInvalidate = [];
      for (const [computedKey, deps] of this._computedDependencies) {
        if (deps.has(path) && !invalidated.has(computedKey)) {
          keysToInvalidate.push(computedKey);
        }
      }
      
      // Then invalidate them
      for (const computedKey of keysToInvalidate) {
        this._computedCache.delete(computedKey);
        this._computedDependencies.delete(computedKey);
        invalidated.add(computedKey);
        // If other computed props depend on this one, invalidate them too
        toInvalidate.push(computedKey);
      }
    }
  }

  _wrap(obj, path = [], isRoot = false) {
    if (this._isDestroyed) return obj;
    if (typeof obj !== 'object' || obj === null) return obj;
    
    // Prevent stack overflow on deeply nested objects
    if (path.length > this._maxDepth) {
      return obj; // Return unwrapped object beyond max depth (no reactivity)
    }
    
    // Return cached proxy if exists (but not for root - we need special handling)
    if (!isRoot && this._proxyCache.has(obj)) {
      return this._proxyCache.get(obj);
    }
    
    if (Array.isArray(obj)) {
      return this._wrapArray(obj, path);
    }
    
    const proxy = new Proxy(obj, {
      get: (t, prop) => {
        if (this._isDestroyed) return t[prop];
        
        const propStr = String(prop);
        
        // Handle computed properties at root level
        if (isRoot && propStr in this._computed) {
          // Track dependency on this computed property if we're evaluating another computed
          // (allows computed-on-computed dependency chains like: postCount → filteredPosts → posts)
          if (this._tracking && this._currentComputedKey && this._currentComputedKey !== propStr) {
            this._accessedPaths.add(propStr);
          }
          return this._getComputedValue(propStr, this._computed[propStr]);
        }
        
        // Track dependency if we're evaluating a computed property
        if (this._tracking && this._currentComputedKey) {
          const fullPath = path.length > 0 ? path.concat(prop).join('.') : propStr;
          this._accessedPaths.add(fullPath);
        }
        
        const v = t[prop];
        return (typeof v === 'object' && v !== null) ? this._wrap(v, path.concat(prop)) : v;
      },
      set: (t, prop, val) => {
        if (this._isDestroyed) return false;
        this._runHooks('beforeSet', t, prop, val, path);
        const old = t[prop];
        if (old !== val) {
          // Invalidate cache if replacing an object
          if (typeof old === 'object' && old !== null) {
            this._proxyCache.delete(old);
          }
          t[prop] = val;
          
          const fullPath = path.concat(prop).join('.');
          
          // Invalidate computed properties that depend on this path
          this._invalidateComputed(String(prop));
          if (path.length > 0) {
            this._invalidateComputed(fullPath);
          }
          
          this._notify(fullPath, val, old);
        }
        this._runHooks('afterSet', t, prop, val, path);
        return true;
      },
      // Make computed properties visible to 'in' operator and property checks
      has: (t, prop) => {
        const propStr = String(prop);
        // Check computed properties at root level
        if (isRoot && propStr in this._computed) {
          return true;
        }
        return prop in t;
      },
      // Include computed properties in Object.keys(), for...in, etc.
      ownKeys: (t) => {
        const keys = Reflect.ownKeys(t);
        // Add computed property keys at root level
        if (isRoot) {
          const computedKeys = Object.keys(this._computed);
          for (const key of computedKeys) {
            if (!keys.includes(key)) {
              keys.push(key);
            }
          }
        }
        return keys;
      },
      // Return property descriptors for computed properties
      getOwnPropertyDescriptor: (t, prop) => {
        const propStr = String(prop);
        // Handle computed properties at root level
        if (isRoot && propStr in this._computed) {
          return {
            configurable: true,
            enumerable: true,
            value: this._getComputedValue(propStr, this._computed[propStr])
          };
        }
        return Object.getOwnPropertyDescriptor(t, prop);
      }
    });
    
    // Cache the proxy (but not root - it has special computed handling)
    if (!isRoot) {
      this._proxyCache.set(obj, proxy);
    }
    return proxy;
  }

  _wrapArray(arr, path) {
    // Prevent stack overflow on deeply nested arrays
    if (path.length > this._maxDepth) {
      return arr; // Return unwrapped array beyond max depth (no reactivity)
    }
    
    // Return cached proxy if exists
    if (this._proxyCache.has(arr)) {
      return this._proxyCache.get(arr);
    }
    
    const proxy = new Proxy(arr, {
      get: (t, prop) => {
        if (this._isDestroyed) return t[prop];
        
        // Track dependency if we're evaluating a computed property
        if (this._tracking && this._currentComputedKey) {
          const fullPath = path.concat(prop).join('.');
          this._accessedPaths.add(fullPath);
        }
        
        if (typeof t[prop] === 'function') return this._wrapArrayMethod(t, prop, path);
        const v = t[prop];
        return (typeof v === 'object' && v !== null) ? this._wrap(v, path.concat(prop)) : v;
      },
      set: (t, prop, val) => {
        if (this._isDestroyed) return false;
        const old = t[prop];
        if (old !== val) {
          // Invalidate cache if replacing an object
          if (typeof old === 'object' && old !== null) {
            this._proxyCache.delete(old);
          }
          t[prop] = val;
          if (!isNaN(prop)) {
            const fullPath = path.concat(prop).join('.');
            this._invalidateComputed(fullPath);
            this._notify(fullPath, val);
            this._notify(path.concat('length').join('.'), t.length);
          }
        }
        return true;
      }
    });
    
    // Cache the proxy
    this._proxyCache.set(arr, proxy);
    return proxy;
  }

  _wrapArrayMethod(target, name, path) {
    const orig = target[name];
    const mutators = ['push','pop','shift','unshift','splice','sort','reverse','fill','copyWithin'];
    return function(...args) {
      if (this._isDestroyed) return orig.apply(target, args);
      const oldLen = target.length;
      const res = orig.apply(target, args);
      if (mutators.includes(name)) {
        const arrayPath = path.join('.');
        this._invalidateComputed(arrayPath);
        this._notify(arrayPath, target);
        if (target.length !== oldLen) this._notify(path.concat('length').join('.'), target.length);
      }
      return res;
    }.bind(this);
  }

  _addWatcher(key, handler) {
    if (key.endsWith('.**')) {
      const prefix = key.slice(0, -3);
      if (!this._deepWildcards.has(prefix)) {
        this._deepWildcards.set(prefix, new Set());
      }
      this._deepWildcards.get(prefix).add(handler);
    } else if (key.endsWith('.*')) {
      const prefix = key.slice(0, -2);
      if (!this._shallowWildcards.has(prefix)) {
        this._shallowWildcards.set(prefix, new Set());
      }
      this._shallowWildcards.get(prefix).add(handler);
    } else {
      this._exactWatchers.set(key, handler);
    }
  }

  _removeWatcher(key) {
    if (key.endsWith('.**')) {
      const prefix = key.slice(0, -3);
      this._deepWildcards.delete(prefix);
    } else if (key.endsWith('.*')) {
      const prefix = key.slice(0, -2);
      this._shallowWildcards.delete(prefix);
    } else {
      this._exactWatchers.delete(key);
    }
  }

  _clearAllWatchers() {
    this._exactWatchers.clear();
    this._shallowWildcards.clear();
    this._deepWildcards.clear();
  }

  _setupProxyMethods() {
    // Helper to define and register core methods
    const defineCoreMethod = (name, fn) => {
      Object.defineProperty(this._proxy, name, { 
        value: fn, 
        enumerable: false,
        configurable: false,  // Core methods cannot be overridden
        writable: false
      });
      this._registerMethod(name, 'core', false);
    };
    
    defineCoreMethod('$onChange', fn => { 
      this._onChange = fn; 
      return this._proxy; 
    });
    
    defineCoreMethod('$watch', (key, handler) => { 
      if (typeof handler === 'function') { 
        this._addWatcher(key, handler); 
        return () => this._proxy.$unwatch(key); 
      } 
      return this._proxy; 
    });
    
    defineCoreMethod('$unwatch', key => { 
      this._removeWatcher(key); 
      return this._proxy; 
    });
    
    defineCoreMethod('$set', u => (
      typeof u === 'function' ? this._bulk(u) : this._bulk(s => { this._applyUpdates(s, u); })
    ));
    
    // Computed properties - define computed getters
    defineCoreMethod('$computed', obj => { 
      // Skip reserved keys that could cause prototype pollution
      const RESERVED_KEYS = ['__proto__', 'constructor', 'prototype'];
      for (const [key, fn] of Object.entries(obj)) {
        if (RESERVED_KEYS.includes(key)) {
          console.warn(`restate: Skipping reserved computed key '${key}'`);
          continue;
        }
        if (typeof fn !== 'function') {
          console.warn(`restate: Computed property '${key}' must be a function`);
          continue;
        }
        this._computed[key] = fn;
      }
      return this._proxy; 
    });
    
    // Get computed dependencies for debugging
    defineCoreMethod('$dependencies', () => {
      const out = {};
      for (const [key, deps] of this._computedDependencies) {
        out[key] = Array.from(deps);
      }
      return out;
    });
    
    // Define custom methods on the state proxy (with collision detection)
    defineCoreMethod('$methods', methods => {
      Object.entries(methods).forEach(([name, fn]) => {
        if (typeof fn !== 'function') {
          throw new Error(`restate: Method '${name}' must be a function`);
        }
        
        // Check for collisions with core methods
        if (CORE_METHODS.includes(name)) {
          throw new Error(`restate: Cannot define method '${name}' - it's a reserved core method`);
        }
        
        // Check for reserved prefixes
        if (this._isReservedPrefix(name)) {
          throw new Error(`restate: Cannot define method '${name}' - names starting with '_' are reserved`);
        }
        
        // Check collision with plugin methods (user methods can override other user methods)
        const existing = this._methodRegistry.get(name);
        if (existing && existing.source.startsWith('plugin:')) {
          console.warn(
            `restate: $methods() is overriding '${name}' (previously defined by ${existing.source})`
          );
        }
        
        Object.defineProperty(this._proxy, name, {
          value: fn.bind(this._proxy),
          enumerable: false,
          writable: true,
          configurable: true
        });
        
        // Register as user method
        this._registerMethod(name, 'user', true);
      });
      return this._proxy;
    });
    
    // Get method registry for debugging
    defineCoreMethod('$registry', () => {
      const out = {};
      for (const [name, info] of this._methodRegistry) {
        out[name] = { ...info };
        // Don't expose originalFn in the output
        delete out[name].originalFn;
      }
      return out;
    });
    
    defineCoreMethod('$destroy', () => { 
      this._runHooks('onDestroy'); 
      this._isDestroyed = true; 
      this._clearAllWatchers(); 
      this._onChange = null; 
      this._plugins.clear();
      this._pluginLoadOrder = [];
      this._methodRegistry.clear();
      this._proxyCache = new WeakMap();
      // Clear computed state
      this._computed = {};
      this._computedDependencies.clear();
      this._computedCache.clear();
      if (this._computedCallStack) this._computedCallStack.clear();
      return this._proxy; 
    });
  }

  _applyUpdates(target, updates, path=[]) {
    if (this._isDestroyed) return;
    // Keys that could cause prototype pollution
    const DANGEROUS_KEYS = ['__proto__', 'constructor', 'prototype'];
    for (const [k, v] of Object.entries(updates)) {
      // Skip dangerous keys to prevent prototype pollution
      if (DANGEROUS_KEYS.includes(k)) continue;
      if (typeof v === 'object' && v !== null && !Array.isArray(v)) {
        if (!target[k] || typeof target[k] !== 'object') target[k] = {};
        this._applyUpdates(target[k], v, path.concat(k));
      } else {
        target[k] = v;
      }
    }
  }
}

// Chainable store factory
export function restate(initialState = {}) {
  const instance = new restateCore(initialState, { plugins: [] });
  const proxy = instance._proxy;
  proxy.use = function(pluginFactory, options) {
    const plugin = typeof pluginFactory === 'function' ? pluginFactory(instance) : pluginFactory;
    instance.use(plugin);
    return instance._proxy;
  };
  return proxy;
}
